import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the fused CUDA kernel
fused_linear_min_sub_source = """
#include <torch/extension.h>
#include <cuda.h>
#include <cuda_runtime.h>

template<typename T>
__global__ void fused_linear_min_sub_kernel(
    const T* __restrict__ input,
    const T* __restrict__ weight,
    const T* __restrict__ bias,
    T* __restrict__ output,
    T constant,
    int batch_size,
    int in_features,
    int out_features) {

    // Thread indices
    int row = blockIdx.y * blockDim.y + threadIdx.y;
    int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < batch_size && col < out_features) {
        T sum = static_cast<T>(0);

        // Compute dot product
        for (int k = 0; k < in_features; ++k) {
            sum += input[row * in_features + k] * weight[col * in_features + k];
        }

        // Add bias if provided
        if (bias != nullptr) {
            sum += bias[col];
        }

        // Fused operations: min(constant, sum) - constant
        T result = sum < constant ? sum : constant;
        result -= constant;

        output[row * out_features + col] = result;
    }
}

torch::Tensor fused_linear_min_sub_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float constant) {

    // Get tensor dimensions
    int batch_size = input.size(0);
    int in_features = input.size(1);
    int out_features = weight.size(0);

    // Create output tensor
    auto output = torch::empty({batch_size, out_features},
                              torch::TensorOptions()
                              .dtype(input.dtype())
                              .device(input.device()));

    // Configure kernel launch parameters
    dim3 block_size(16, 16);
    dim3 grid_size((out_features + block_size.x - 1) / block_size.x,
                   (batch_size + block_size.y - 1) / block_size.y);

    // Dispatch based on data type
    AT_DISPATCH_FLOATING_TYPES(input.scalar_type(), "fused_linear_min_sub_cuda", ([&] {
        fused_linear_min_sub_kernel<scalar_t><<<grid_size, block_size>>>(
            input.data_ptr<scalar_t>(),
            weight.data_ptr<scalar_t>(),
            bias.defined() ? bias.data_ptr<scalar_t>() : nullptr,
            output.data_ptr<scalar_t>(),
            static_cast<scalar_t>(constant),
            batch_size,
            in_features,
            out_features);
    }));

    return output;
}
"""

fused_linear_min_sub_cpp_source = """
torch::Tensor fused_linear_min_sub_cuda(
    torch::Tensor input,
    torch::Tensor weight,
    torch::Tensor bias,
    float constant);
"""

# Compile the inline CUDA code
fused_linear_min_sub = load_inline(
    name="fused_linear_min_sub",
    cpp_sources=fused_linear_min_sub_cpp_source,
    cuda_sources=fused_linear_min_sub_source,
    functions=["fused_linear_min_sub_cuda"],
    verbose=False,
    extra_cflags=["-O3"],
    extra_ldflags=[],
    with_cuda=True,
)

class ModelNew(nn.Module):
    """
    Optimized model with fused linear + min + subtract operation.
    """
    def __init__(self, in_features, out_features, constant):
        super(ModelNew, self).__init__()
        self.in_features = in_features
        self.out_features = out_features

        # Store constant as a buffer (not trainable parameter)
        self.register_buffer('constant', torch.tensor(constant, dtype=torch.float32))

        # Initialize weight and bias like nn.Linear
        self.weight = nn.Parameter(torch.empty(out_features, in_features, dtype=torch.float32))
        self.bias = nn.Parameter(torch.empty(out_features, dtype=torch.float32))

        # Initialize parameters
        nn.init.kaiming_uniform_(self.weight, a=5**0.5)
        fan_in, _ = nn.init._calculate_fan_in_and_fan_out(self.weight)
        bound = 1 / (fan_in ** 0.5)
        nn.init.uniform_(self.bias, -bound, bound)

    def forward(self, x):
        # Ensure input is on CUDA and in float32
        if not x.is_cuda:
            x = x.cuda()
        if x.dtype != torch.float32:
            x = x.to(torch.float32)

        return fused_linear_min_sub.fused_linear_min_sub_cuda(
